def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.05:
                score += (0.05 - temp_ratio) ** 3 * 2
            elif 0.05 <= temp_ratio < 0.2:
                score += (0.2 - temp_ratio) * 1.5
            elif 0.2 <= temp_ratio < 0.7:
                score += np.log1p(temp_ratio) * 0.8
            else:
                score += np.exp(-temp_ratio)
            temp_ratio = np.power(temp_ratio, 0.75)
        if capacity < 10:
            score *= 1.2
        elif 10 <= capacity < 50:
            score *= 0.9
        else:
            score *= 1.0 + (np.sin(capacity) / 10)
        if item < 5:
            for k in range(3):
                if score < 1:
                    score += 0.1 * (k+1)
                else:
                    score -= 0.05 * k
                if score < 0:
                    score = 0
        priorities[i] = score
    max_priority = np.max(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 1
    return priorities
